var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"이, 이건 엘릭서?","JPN":"こ、これはエリクサー？","ENG":"I-isn't that the Elixir?","TWN":"這，這是聖水？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"이 약물에 대해 아는 눈치네요?","JPN":"この薬物について知っているようですね。","ENG":"You seem to recognize it.","TWN":"你似乎知道這種藥物？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"소문으로만 들었네.","JPN":"噂で聞いたことがある。","ENG":"I've only heard rumors.","TWN":"只是聽說過。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"일반인에게 카운터와 비견되는 힘을 가져다주는 약물로 알고 있지.","JPN":"一般人にもカウンターに匹敵する力を与えてくれる薬物だと聞いた。","ENG":"The Elixir said to grant ordinary people power comparable to Counters.","TWN":"我知道這是一種能讓普通人擁有媲美制裁者力量的藥物。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"하지만…… 심각한 부작용을 초래한다고 하더군.","JPN":"しかし……深刻な副作用が伴うらしい。","ENG":"But... it supposedly comes with severe side effects.","TWN":"但是……聽說有嚴重的副作用。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"제조법 또한 관리국에서 엄중히 관리하고 있다네.","JPN":"製造法も管理局で厳重に管理されている。","ENG":"Not to mention, the formula is strictly controlled by the Administration.","TWN":"製造方法在管理局手裡。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"자네가 누구인지는 모르겠지만, 엘릭서 자체가 불법이란 소리일세.","JPN":"君が誰かは知らないが、エリクサー自体、違法薬物だということだ。","ENG":"I don't know who you are, but the Elixir itself is illegal.","TWN":"不知道你是誰，但我可以告訴你，聖水本身就是非法的。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"하하. 그건 걱정할 필요 없습니다.","JPN":"はは。それはご心配なく。","ENG":"Haha. That's not something you need to worry about.","TWN":"哈哈，不用擔心。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"제가 직접 제조한 것들이거든요.","JPN":"僕が自分で作ったものなので。","ENG":"After all, I made these myself.","TWN":"這些都是我親手製作的。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"직접 만들었다고 해서 합법이 되지는 않네.","JPN":"自分で作ったからと言って合法にはならない。","ENG":"Just because you made it doesn't make it legal.","TWN":"自己做的也不代表合法。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"당신이 <color=#ffd34c>겪은 일</color>에 대해선 유감입니다. 루드윅 폰 에르헨 박사님.","JPN":"あなたが<color=#ffd34c>経験したこと</color>については、非常に残念だと思っています。ルードヴィヒ・フォン・ヘルヒェン博士。","ENG":"I must say, I sympathize with <color=#ffd34c>what you've been through</color>, Dr. Ludwig von Herrchen.","TWN":"對於你<color=#ffd34c>經歷的事情</color>，我深感遺憾，路易博士。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"당신의 침식학 논문들을 꽤 흥미롭게 봤어요.","JPN":"あなたが書いた侵食学の論文は非常に興味深いものでした。","ENG":"I've found your research on Corruption quite fascinating.","TWN":"我對你的侵蝕學論文非常感興趣。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"그건 제 흥미를 충족해 준 답례라고 생각하고 받아주면 좋겠군요.","JPN":"僕の好奇心を満たしてくれたお礼だと思って、受け取って欲しいのです。","ENG":"Consider this my way of returning the favor.","TWN":"那就當作是你滿足我的興趣的謝禮吧，希望你能接受。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"나에게 왜 이러는 거지?","JPN":"なぜ私にこんなことをする？","ENG":"Why are you doing this?","TWN":"為什麼要送我？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"말씀드렸잖아요. 당신의 논문을 흥미롭게 봤고, 그에 대한 답례라고.","JPN":"言ったじゃないですか。あなたの論文を興味深く読ませていただいたことへのお礼だと。","ENG":"I already told you. I was impressed by your research, and this is my way of showing appreciation.","TWN":"我不是說過了嗎？我對你的論文很感興趣，這是對你的答謝。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"특히나, 박사님이 마지막으로 썼던 논문이 인상 깊었어요.","JPN":"特に、博士が最後に書いた論文が印象的でした。","ENG":"Your last paper, in particular, left quite an impression.","TWN":"尤其是博士最後寫的那篇論文，給我留下了深刻的印象。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"<color=#ffd34c>이상 침식 현상으로 인한 유전자 변화와 내재한 인자의 가능성</color>.","JPN":"<color=#ffd34c>異常侵食現象による遺伝子の変化および内在ファクターの可能性について</color>。","ENG":"<color=#ffd34c>Genetic Alterations from the Aberrant Counterside Effect and the Potential of Latent Factors</color>.","TWN":"<color=#ffd34c>由異常侵蝕現象引起基因變化和產生內在因子的可能性</color>。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"완성되지 못한 채 세상 밖으로 나온 실패작이지.","JPN":"未完成のまま世に出てしまった失敗作だ。","ENG":"A failure that was released into the world incomplete.","TWN":"尚未完成就被帶到世上的失敗作。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"엘릭서는 못 본 척해줄 테니…….","JPN":"エリクサーのことは見逃してやるから……","ENG":"I'll pretend you never showed me the Elixir, so–","TWN":"我會假裝沒看到聖水……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"제가 마침 침식학과 유전공학에도 관심이 있었거든요.","JPN":"僕、ちょうど侵食学と遺伝子工学にも興味があるんです。","ENG":"As it happens, I have a keen interest in both Corruption and genetic engineering.","TWN":"我正好對侵蝕學和遺傳學也感興趣。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"박사님의 연구에 대해 더 자세히 알 수 있을까요?","JPN":"あなたの研究について、詳しく聞かせてくれませんか？","ENG":"Would you be willing to share more details about your research?","TWN":"能詳細了解一下博士的研究嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"……거절하겠네.","JPN":"……断る。","ENG":"...I decline.","TWN":"……我拒絕。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"나는 이미 학계에서 은퇴하고, 죽을 날만 기다리는 사람이야.","JPN":"私はもう学会を引退し、死を待つだけの人間だ。","ENG":"I've already retired from academia. I'm just waiting for my time to run out.","TWN":"我已經從學界退休，現在只是在等待死亡的那一天。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"아쉽군요.","JPN":"残念ですね。","ENG":"What a shame.","TWN":"好可惜喔……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"당신이라면 저 실패를 딛고 나아가, 새로운 지평을 열 수 있을 텐데.","JPN":"あなたならあの失敗を乗り越え、新境地を開けるはずなのに。","ENG":"You, of all people, could rise above failure and open new doors for humanity.","TWN":"如果是你的話，一定能克服失敗，開創新的局面。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};